class Solution:
    def getBiggestThree(self, grid):
        m = len(grid)
        n = len(grid[0])
        sums = set()
        for r in range(m):
            for c in range(n):
                sums.add(grid[r][c])  # size 0
                k = 1
                while True:
                    top = (r, c)
                    right = (r + k, c + k)
                    bottom = (r + 2 * k, c)
                    left = (r + k, c - k)
                    if bottom[0] >= m or right[1] >= n or left[1] < 0:
                        break
                    total = 0
                    # top -> right edge
                    for i in range(k):
                        total += grid[r + i][c + i]
                    # right -> bottom
                    for i in range(k):
                        total += grid[r + k + i][c + k - i]
                    # bottom -> left
                    for i in range(k):
                        total += grid[r + 2 * k - i][c - i]
                    # left -> top
                    for i in range(k):
                        total += grid[r + k - i][c - k + i]
                    sums.add(total)
                    k += 1
        top3 = sorted(sums, reverse=True)[:3]
        return top3

