class Solution:
    def getBiggestThree(self, grid):
        m = len(grid)
        n = len(grid[0])
        # prefix along the two diagonal directions
        # d1: down-right (r-c constant), d2: down-left (r+c constant)
        dr = [[0] * (n + 1) for _ in range(m + 1)]
        dl = [[0] * (n + 2) for _ in range(m + 1)]
        for r in range(m):
            for c in range(n):
                dr[r + 1][c + 1] = (dr[r][c] if c >= 0 else 0) + grid[r][c]
        for r in range(m):
            for c in range(n):
                dl[r + 1][c] = dl[r][c + 1] + grid[r][c]
        def diag_dr(r, c, length):
            # sum of cells (r,c),(r+1,c+1)... length cells, down-right
            return dr[r + length][c + length] - dr[r][c]
        def diag_dl(r, c, length):
            # sum of cells (r,c),(r+1,c-1)... length cells, down-left
            return dl[r + length][c - length + 1] - dl[r][c + 1]
        sums = set()
        for r in range(m):
            for c in range(n):
                sums.add(grid[r][c])
                k = 1
                while r + 2 * k < m and c + k < n and c - k >= 0:
                    a = diag_dr(r, c, k + 1)
                    b = diag_dr(r + k, c - k, k + 1)
                    cc = diag_dl(r, c, k + 1)
                    d = diag_dl(r + k, c + k, k + 1)
                    total = a + b + cc + d - grid[r][c] - grid[r + k][c + k] - grid[r + 2 * k][c] - grid[r + k][c - k]
                    sums.add(total)
                    k += 1
        return sorted(sums, reverse=True)[:3]

