var getBiggestThree = function(grid) {
    const m = grid.length, n = grid[0].length;
    const dr = Array.from({length: m + 1}, () => new Array(n + 1).fill(0));
    const dl = Array.from({length: m + 1}, () => new Array(n + 2).fill(0));
    for (let r = 0; r < m; r++)
        for (let c = 0; c < n; c++)
            dr[r + 1][c + 1] = dr[r][c] + grid[r][c];
    for (let r = 0; r < m; r++)
        for (let c = 0; c < n; c++)
            dl[r + 1][c] = dl[r][c + 1] + grid[r][c];
    const diagDr = (r, c, length) => dr[r + length][c + length] - dr[r][c];
    const diagDl = (r, c, length) => dl[r + length][c - length + 1] - dl[r][c + 1];
    const sums = new Set();
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            sums.add(grid[r][c]);
            let k = 1;
            while (r + 2 * k < m && c + k < n && c - k >= 0) {
                const a = diagDr(r, c, k + 1);
                const b = diagDr(r + k, c - k, k + 1);
                const cc = diagDl(r, c, k + 1);
                const d = diagDl(r + k, c + k, k + 1);
                const total = a + b + cc + d - grid[r][c] - grid[r + k][c + k] - grid[r + 2 * k][c] - grid[r + k][c - k];
                sums.add(total);
                k++;
            }
        }
    }
    return Array.from(sums).sort((x, y) => y - x).slice(0, 3);
};
